INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FSA-11'), 'FSA-11-LO01', 'Describe the common tools and techniques used in financial statement analysis, including ratio analysis, common-size statements, trend analysis, and regression analysis, and explain how each technique supports the evaluation of a company''s financial position and performance.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FSA-11'), 'FSA-11-LO02', 'Calculate and interpret activity, liquidity, solvency, profitability, and valuation ratios from a company''s financial statements, and explain what each ratio reveals about operational efficiency, financial risk, and value creation.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='FSA-11'), 'FSA-11-LO03', 'Analyze the DuPont decomposition of return on equity into its component ratios—net profit margin, asset turnover, and financial leverage—and apply the extended five-factor DuPont framework to identify the specific drivers of changes in a company''s ROE over time.', 4, 3),
    ((SELECT id FROM learning_modules WHERE code='FSA-11'), 'FSA-11-LO04', 'Construct and interpret common-size income statements and balance sheets, and explain how vertical and horizontal common-size analysis facilitates comparisons across companies of different sizes and across reporting periods.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='FSA-11'), 'FSA-11-LO05', 'Evaluate the limitations of ratio analysis, including the effects of accounting method choices, seasonality, non-recurring items, and differences in business models, and explain how these factors can distort cross-sectional and time-series comparisons.', 5, 5),
    ((SELECT id FROM learning_modules WHERE code='FSA-11'), 'FSA-11-LO06', 'Identify the categories of ratios used to assess credit quality and equity value, and distinguish between the information needs of creditors and equity investors when selecting and interpreting financial ratios.', 2, 6),
    ((SELECT id FROM learning_modules WHERE code='FSA-11'), 'FSA-11-LO07', 'Apply ratio analysis and common-size financial statement data to screen for investment opportunities, assess a company''s competitive position, and forecast future financial performance within a structured analytical framework.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FSA-12'), 'FSA-12-LO01', 'Describe the steps in building an integrated financial statement model, including the linkages among the income statement, balance sheet, and cash flow statement.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FSA-12'), 'FSA-12-LO02', 'Explain how revenue drivers, cost structure assumptions, and working capital policies are translated into projected financial statements.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='FSA-12'), 'FSA-12-LO03', 'Calculate projected revenues, operating expenses, net income, and earnings per share using given assumptions about growth rates, margins, and tax rates.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='FSA-12'), 'FSA-12-LO04', 'Apply the percent-of-sales method and other forecasting techniques to estimate balance sheet items and construct a pro forma cash flow statement consistent with projected income statement and balance sheet changes.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='FSA-12'), 'FSA-12-LO05', 'Analyze the sensitivity of projected financial outcomes to changes in key assumptions, including revenue growth, operating leverage, and financing mix, and interpret the implications for valuation and credit risk.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='FSA-12'), 'FSA-12-LO06', 'Evaluate the quality and reasonableness of a financial statement model by comparing its outputs against historical trends, industry benchmarks, and internally consistent accounting relationships.', 5, 6),
    ((SELECT id FROM learning_modules WHERE code='FSA-12'), 'FSA-12-LO07', 'Identify the most common modeling pitfalls—including circular references arising from interest expense forecasts, inconsistent accounting policy assumptions, and failure to balance the balance sheet—and describe how to resolve them.', 2, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='CORP-06'), 'CORP-06-LO01', 'Describe the key propositions of the Modigliani–Miller capital structure theorems under assumptions of no taxes, no financial distress costs, and perfect capital markets, and explain why capital structure is irrelevant to firm value under those conditions.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='CORP-06'), 'CORP-06-LO02', 'Explain how the introduction of corporate taxes and financial distress costs modifies the Modigliani–Miller framework, giving rise to the trade-off theory of optimal capital structure.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='CORP-06'), 'CORP-06-LO03', 'Calculate the value of a levered firm using the Modigliani–Miller proposition with corporate taxes, and interpret the tax shield on debt and its effect on the weighted average cost of capital.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='CORP-06'), 'CORP-06-LO04', 'Compare the trade-off theory, pecking order theory, and agency cost theory of capital structure, distinguishing the primary factors each theory identifies as determinants of a firm''s financing decisions.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='CORP-06'), 'CORP-06-LO05', 'Analyze how factors including business risk, asset tangibility, growth opportunities, profitability, and tax position influence a firm''s target capital structure.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='CORP-06'), 'CORP-06-LO06', 'Evaluate the costs and benefits of debt financing relative to equity financing, including the effects of agency conflicts between shareholders and debtholders, information asymmetry, and signaling on a firm''s capital structure choice.', 5, 6),
    ((SELECT id FROM learning_modules WHERE code='CORP-06'), 'CORP-06-LO07', 'Determine the impact of a change in capital structure on a firm''s weighted average cost of capital, cost of equity, and firm value, applying the relationships among leverage, financial risk, and required rates of return.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='CORP-07'), 'CORP-07-LO01', 'Describe the key features of a business model, including value proposition, pricing strategy, revenue streams, and cost structure, and explain how these features interact to determine a firm''s profitability.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='CORP-07'), 'CORP-07-LO02', 'Distinguish among major business model types—including B2B, B2C, subscription, franchise, platform/network, and freemium models—and identify the primary revenue and cost drivers associated with each.', 4, 2),
    ((SELECT id FROM learning_modules WHERE code='CORP-07'), 'CORP-07-LO03', 'Analyze how network effects, switching costs, and economies of scale embedded in a business model contribute to or erode a firm''s competitive advantage over time.', 4, 3),
    ((SELECT id FROM learning_modules WHERE code='CORP-07'), 'CORP-07-LO04', 'Calculate and interpret key business model metrics—including gross margin, customer acquisition cost (CAC), customer lifetime value (CLV), and the CLV-to-CAC ratio—and evaluate what these metrics reveal about the sustainability of a firm''s business model.', 5, 4),
    ((SELECT id FROM learning_modules WHERE code='CORP-07'), 'CORP-07-LO05', 'Explain how pricing strategies—including cost-plus, value-based, dynamic, and penetration pricing—affect a firm''s revenue model and competitive positioning.', 2, 5),
    ((SELECT id FROM learning_modules WHERE code='CORP-07'), 'CORP-07-LO06', 'Evaluate the risks and limitations of a given business model by identifying factors such as customer concentration, regulatory exposure, technological disruption, and capital intensity that may threaten long-run viability.', 5, 6),
    ((SELECT id FROM learning_modules WHERE code='CORP-07'), 'CORP-07-LO07', 'Compare the unit economics of asset-light versus asset-heavy business models, and determine how differences in fixed and variable cost structures affect operating leverage and breakeven analysis.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='EQU-07'), 'EQU-07-LO01', 'Describe the steps in building a company financial forecast, including the role of top-down and bottom-up approaches in projecting revenues, operating costs, and capital expenditures.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='EQU-07'), 'EQU-07-LO02', 'Explain how industry dynamics, competitive positioning, and macroeconomic drivers are incorporated into revenue forecasts for a company.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='EQU-07'), 'EQU-07-LO03', 'Calculate projected income statement, balance sheet, and cash flow statement items using historical financial data, common-size analysis, and analyst assumptions about growth rates and margins.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='EQU-07'), 'EQU-07-LO04', 'Analyze the sensitivity of a company''s projected earnings and free cash flow to changes in key assumptions, including revenue growth, operating margins, working capital requirements, and capital expenditure levels.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='EQU-07'), 'EQU-07-LO05', 'Distinguish between return on invested capital (ROIC) and return on equity (ROE) as measures of company profitability, and explain how each is used to assess the sustainability of a company''s competitive advantage in a forecast context.', 2, 5),
    ((SELECT id FROM learning_modules WHERE code='EQU-07'), 'EQU-07-LO06', 'Estimate a company''s normalized earnings and free cash flow by adjusting reported financials for non-recurring items, accounting distortions, and cyclical effects.', 3, 6),
    ((SELECT id FROM learning_modules WHERE code='EQU-07'), 'EQU-07-LO07', 'Evaluate the quality of a company''s earnings forecast by identifying red flags in financial statements, including aggressive revenue recognition, understated expenses, and unsustainable working capital trends.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='EQU-08'), 'EQU-08-LO01', 'Describe the major categories of equity valuation models—present value (discounted cash flow), multiplier, and asset-based—and explain the circumstances under which each approach is most appropriate.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='EQU-08'), 'EQU-08-LO02', 'Calculate and interpret the intrinsic value of a common stock using the dividend discount model (DDM) under the Gordon Growth Model assumption, given the required rate of return and a constant dividend growth rate.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='EQU-08'), 'EQU-08-LO03', 'Apply the multistage dividend discount model to estimate the intrinsic value of a stock when dividends are expected to grow at different rates across distinct phases, and determine whether the stock appears overvalued, undervalued, or fairly valued relative to its market price.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='EQU-08'), 'EQU-08-LO04', 'Calculate and interpret price multiples—including price-to-earnings (P/E), price-to-book (P/B), price-to-sales (P/S), and price-to-cash-flow (P/CF)—and compare a stock''s multiples to those of peers and the broader market to assess relative valuation.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='EQU-08'), 'EQU-08-LO05', 'Explain the relationship between the justified leading and trailing P/E ratios and the fundamental drivers of value—dividend payout ratio, required rate of return, and expected earnings growth rate—using the Gordon Growth Model.', 2, 5),
    ((SELECT id FROM learning_modules WHERE code='EQU-08'), 'EQU-08-LO06', 'Distinguish between the enterprise value (EV) to EBITDA multiple and equity-based price multiples, and evaluate the situations in which EV/EBITDA provides a more meaningful basis for comparison across companies with different capital structures or tax rates.', 5, 6),
    ((SELECT id FROM learning_modules WHERE code='EQU-08'), 'EQU-08-LO07', 'Estimate the intrinsic value of a stock using an asset-based valuation approach, and identify the types of companies and conditions for which asset-based models yield the most reliable valuation estimates.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-11'), 'FI-11-LO01', 'Define Macaulay duration, modified duration, and money duration, and explain the economic interpretation of each measure as a sensitivity of bond price to yield changes.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-11'), 'FI-11-LO02', 'Calculate Macaulay duration and modified duration for a fixed-rate bond given its cash flows, yield to maturity, and settlement date, and interpret the resulting values in the context of interest rate risk.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-11'), 'FI-11-LO03', 'Calculate the full price change of a bond using modified duration and money duration for a given parallel shift in yield, and evaluate the accuracy of the duration approximation relative to the actual price change.', 4, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-11'), 'FI-11-LO04', 'Explain how a bond''s coupon rate, maturity, yield level, and embedded options affect its Macaulay and modified duration, and compare the duration characteristics of zero-coupon bonds, premium bonds, and discount bonds.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-11'), 'FI-11-LO05', 'Calculate the duration of a bond portfolio using both the weighted-average duration method and the cash-flow-weighted method, and distinguish between the assumptions and limitations of each approach.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-11'), 'FI-11-LO06', 'Define price value of a basis point (PVBP) and calculate it for a single bond and a bond portfolio, and apply PVBP to determine the number of futures contracts needed to achieve a target portfolio duration.', 3, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-11'), 'FI-11-LO07', 'Explain the limitations of yield-based duration measures, including their reliance on a parallel yield curve shift assumption and their inapplicability to bonds with embedded options, and identify circumstances in which alternative duration measures are more appropriate.', 2, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-12'), 'FI-12-LO01', 'Define convexity and explain why it arises as the second-order effect of yield changes on bond prices, distinguishing it from the first-order effect captured by duration.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-12'), 'FI-12-LO02', 'Calculate the approximate convexity of a bond using the full price changes from an equal upward and downward yield shift, and interpret the resulting measure in terms of the curvature of the price–yield relationship.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-12'), 'FI-12-LO03', 'Estimate the percentage change in a bond''s full price using both duration and convexity, and explain the conditions under which the convexity adjustment is most significant.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-12'), 'FI-12-LO04', 'Compare the convexity characteristics of option-free bonds, callable bonds, putable bonds, and mortgage-backed securities, explaining how embedded options and cash flow uncertainty give rise to negative or positive convexity.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-12'), 'FI-12-LO05', 'Calculate the duration and convexity of a fixed-income portfolio as weighted averages of individual bond measures, and evaluate the limitations of this approach relative to computing portfolio-level sensitivities directly from portfolio cash flows.', 5, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-12'), 'FI-12-LO06', 'Analyze the trade-off between yield, duration, and convexity across bonds with similar durations, explaining why investors accept a lower yield for greater convexity and how this relationship affects relative value in different yield-volatility environments.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-12'), 'FI-12-LO07', 'Distinguish between money convexity and convexity expressed as a percentage measure, and demonstrate how money duration and money convexity are used to quantify the dollar impact of yield changes on a bond position.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-13'), 'FI-13-LO01', 'Distinguish between curve duration measures (modified duration, effective duration) and empirical duration, explaining how each captures a bond''s price sensitivity to interest rate changes under different assumptions about yield curve behavior.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-13'), 'FI-13-LO02', 'Explain how key rate durations (partial durations) decompose a bond''s total interest rate sensitivity into exposures at specific maturities along the yield curve, and identify how non-parallel yield curve shifts affect the relative contribution of each key rate.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-13'), 'FI-13-LO03', 'Calculate key rate durations for a fixed-income security or portfolio and apply them to estimate the price impact of a non-parallel shift in the benchmark yield curve.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-13'), 'FI-13-LO04', 'Describe how empirical duration is estimated using historical regression of bond price returns on benchmark yield changes, and explain why empirical duration may differ materially from analytical duration for securities such as high-yield bonds, mortgage-backed securities, and inflation-linked bonds.', 2, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-13'), 'FI-13-LO05', 'Analyze the conditions under which empirical duration provides a more reliable hedge ratio than modified or effective duration, including the role of credit spread co-movement with benchmark yields and the liquidity characteristics of the bond.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-13'), 'FI-13-LO06', 'Compare the sensitivity of a bond portfolio''s value to changes in the level, slope, and curvature of the yield curve using a factor-based (PCA) framework, and interpret the contribution of each factor to overall portfolio duration risk.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-13'), 'FI-13-LO07', 'Evaluate the limitations of curve-based duration measures when applied to bonds with embedded options or complex cash flow structures, and determine when empirical duration estimates are preferable for risk management and hedging decisions.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-14'), 'FI-14-LO01', 'Describe the key components of credit risk, including default risk, loss severity, and recovery rate, and explain how each component contributes to expected loss.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-14'), 'FI-14-LO02', 'Distinguish between investment-grade and high-yield (speculative-grade) credit ratings, and explain the role of credit rating agencies in assessing issuer and issue-specific credit risk.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-14'), 'FI-14-LO03', 'Calculate expected loss given default probability, loss given default, and exposure at default, and interpret the resulting measure in the context of fixed income portfolio risk.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-14'), 'FI-14-LO04', 'Explain the factors that influence a bond''s credit spread, including the business cycle, industry conditions, company fundamentals, and debt seniority, and analyze how changes in these factors affect spread levels.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-14'), 'FI-14-LO05', 'Compare the priority of claims in a corporate liquidation or reorganization across the capital structure, including secured debt, senior unsecured debt, subordinated debt, and equity, and evaluate the implications for recovery rates.', 5, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-14'), 'FI-14-LO06', 'Identify the key financial ratios and qualitative factors used in corporate credit analysis, including leverage ratios, coverage ratios, and competitive position, and apply them to assess an issuer''s creditworthiness.', 3, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-14'), 'FI-14-LO07', 'Analyze the relationship between credit spreads and bond prices, and determine the impact of spread widening or tightening on the return of a fixed income security relative to a benchmark.', 4, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-15'), 'FI-15-LO01', 'Describe the key factors used to assess the creditworthiness of sovereign government issuers, including fiscal balance, debt burden, economic growth, monetary policy flexibility, and institutional strength.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-15'), 'FI-15-LO02', 'Distinguish between local-currency and foreign-currency sovereign debt obligations, explaining why ratings and default risk typically differ between the two and the role of a central bank''s monetary authority in that distinction.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-15'), 'FI-15-LO03', 'Analyze a sovereign issuer''s debt sustainability by calculating and interpreting key fiscal metrics—including the debt-to-GDP ratio, primary fiscal balance, and interest coverage—and evaluating their implications for credit quality.', 4, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-15'), 'FI-15-LO04', 'Compare the credit analysis frameworks applied to non-sovereign (sub-national) government issuers and supranational entities with those applied to sovereign issuers, identifying the structural features—such as revenue autonomy, explicit guarantees, and preferred creditor status—that differentiate their default risk profiles.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-15'), 'FI-15-LO05', 'Explain how political risk, governance quality, and willingness to pay interact with economic capacity in determining sovereign credit ratings, and describe how rating agencies incorporate these qualitative factors alongside quantitative metrics.', 2, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-15'), 'FI-15-LO06', 'Evaluate the credit risk implications of a sovereign''s external vulnerability by interpreting indicators such as the current account balance, foreign exchange reserves relative to short-term external debt, and reliance on external financing.', 5, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-15'), 'FI-15-LO07', 'Identify the primary sources of credit risk specific to municipal and other sub-sovereign issuers, including revenue concentration, pension and other post-employment benefit obligations, and legal limitations on taxing or borrowing authority.', 2, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-16'), 'FI-16-LO01', 'Describe the key components of credit risk—default probability, loss given default, and expected loss—and explain how each component influences the credit spread demanded by investors in corporate bonds.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-16'), 'FI-16-LO02', 'Distinguish between the four Cs of credit analysis (capacity, collateral, covenants, and character) and explain how each factor is assessed when evaluating the creditworthiness of a corporate issuer.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-16'), 'FI-16-LO03', 'Calculate and interpret key credit ratios—including debt-to-EBITDA, EBITDA interest coverage, free cash flow to debt, and return on capital—and evaluate what each ratio reveals about an issuer''s ability to service and repay its obligations.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-16'), 'FI-16-LO04', 'Analyze the relationship between credit ratings assigned by major rating agencies and corporate bond yield spreads, including the impact of rating migration and the limitations of relying solely on agency ratings in credit analysis.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-16'), 'FI-16-LO05', 'Explain the role of corporate bond covenants—both affirmative and negative—in protecting bondholders, and evaluate how covenant strength or weakness affects credit risk and the required yield spread.', 5, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-16'), 'FI-16-LO06', 'Compare the credit risk profiles of investment-grade and high-yield corporate issuers, including differences in leverage, cash flow stability, covenant protections, and the primary drivers of default risk for each category.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-16'), 'FI-16-LO07', 'Determine the expected return impact of credit spread changes on a corporate bond position by applying duration and spread duration to estimate price changes resulting from spread widening or tightening.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-17'), 'FI-17-LO01', 'Describe the securitization process, including the roles of the originator, special purpose entity (SPE), servicer, and investors, and explain how securitization transfers credit risk from originators to capital markets.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-17'), 'FI-17-LO02', 'Explain how the structure of a securitization transaction — including the asset pool, cash flow waterfall, credit enhancements, and tranching — determines the risk and return characteristics of each security class.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-17'), 'FI-17-LO03', 'Distinguish between internal credit enhancements (overcollateralization, excess spread, reserve accounts, and subordination) and external credit enhancements (financial guarantees, letters of credit), and evaluate their effectiveness in protecting senior tranche investors.', 5, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-17'), 'FI-17-LO04', 'Calculate the prepayment speed of a mortgage pool using the Conditional Prepayment Rate (CPR) and Single Monthly Mortality (SMM), and interpret the impact of prepayment risk on the cash flows and weighted-average life of mortgage-backed securities.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-17'), 'FI-17-LO05', 'Compare the cash flow characteristics and investor risk exposures of agency mortgage-backed securities (MBS), non-agency MBS, collateralized mortgage obligations (CMOs), and commercial mortgage-backed securities (CMBS), including the role of extension risk and contraction risk.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-17'), 'FI-17-LO06', 'Distinguish among the major types of non-mortgage asset-backed securities (ABS) — including auto loan ABS, credit card ABS, and student loan ABS — with respect to their underlying collateral, payment structures, and key risks.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-17'), 'FI-17-LO07', 'Analyze the benefits and risks of securitization from the perspectives of originators, investors, and the broader financial system, including the potential for moral hazard and systemic risk arising from the originate-to-distribute model.', 4, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-18'), 'FI-18-LO01', 'Describe the structural features of asset-backed securities (ABS), including the roles of the originator, special purpose entity (SPE), servicer, and credit enhancement mechanisms in the securitization process.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-18'), 'FI-18-LO02', 'Distinguish among the collateral characteristics, cash flow structures, and risk profiles of mortgage-backed securities (MBS), auto loan ABS, credit card ABS, and collateralized debt obligations (CDOs).', 4, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-18'), 'FI-18-LO03', 'Explain how prepayment risk arises in mortgage-backed securities and interpret prepayment measures, including the conditional prepayment rate (CPR) and the Public Securities Association (PSA) prepayment benchmark, in the context of MBS cash flow analysis.', 2, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-18'), 'FI-18-LO04', 'Calculate the projected monthly cash flows of a mortgage pass-through security given the pool balance, coupon rate, prepayment assumption expressed as a PSA multiple, and scheduled principal and interest components.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-18'), 'FI-18-LO05', 'Analyze how collateralized mortgage obligation (CMO) structures, including sequential-pay tranches, planned amortization class (PAC) tranches, and support tranches, redistribute prepayment risk among investors.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-18'), 'FI-18-LO06', 'Determine the weighted average life (WAL) of an ABS tranche under different prepayment scenarios and evaluate how changes in prepayment speed affect the extension risk and contraction risk borne by each tranche.', 5, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-18'), 'FI-18-LO07', 'Apply the static spread (Z-spread) and the option-adjusted spread (OAS) frameworks to value an ABS instrument, and interpret the difference between the Z-spread and OAS as a measure of the embedded prepayment option cost.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='FI-19'), 'FI-19-LO01', 'Describe the structure and cash flow characteristics of agency and non-agency mortgage-backed securities, including pass-through securities, collateralized mortgage obligations (CMOs), and commercial mortgage-backed securities (CMBS).', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='FI-19'), 'FI-19-LO02', 'Explain how prepayment risk arises in mortgage-backed securities and distinguish between contraction risk and extension risk as they affect different tranches of a CMO structure.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='FI-19'), 'FI-19-LO03', 'Calculate the weighted average coupon (WAC), weighted average maturity (WAM), and weighted average life (WAL) of a mortgage pass-through security given a pool of individual mortgage loans.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='FI-19'), 'FI-19-LO04', 'Interpret the Public Securities Association (PSA) prepayment benchmark and apply a given PSA speed assumption to project monthly prepayments, scheduled principal, and total cash flows for a mortgage pass-through security.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='FI-19'), 'FI-19-LO05', 'Analyze how sequential-pay, planned amortization class (PAC), and support tranche structures redistribute prepayment risk among CMO investors, and evaluate the trade-offs in yield and risk exposure for each tranche type.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='FI-19'), 'FI-19-LO06', 'Determine the option-adjusted spread (OAS), zero-volatility spread (Z-spread), and nominal spread for a mortgage-backed security and explain how each measure accounts for or ignores the embedded prepayment option when assessing relative value.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='FI-19'), 'FI-19-LO07', 'Compare the credit enhancement mechanisms, loan-level underwriting standards, and default risk characteristics of agency MBS, non-agency residential MBS, and CMBS, and evaluate how these features affect the securities'' risk–return profiles.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='DER-05'), 'DER-05-LO01', 'Explain the no-arbitrage principle and how it establishes the relationship between the forward price of an asset and its current spot price, risk-free rate, and time to expiration.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='DER-05'), 'DER-05-LO02', 'Calculate the no-arbitrage forward price for equity, fixed-income, currency, and commodity forward contracts, incorporating carry costs and carry benefits such as dividends, coupon income, convenience yield, and storage costs.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='DER-05'), 'DER-05-LO03', 'Distinguish between the forward price and the value of a forward contract, and explain how the value of a long or short forward position changes over the life of the contract as the spot price and time to expiration change.', 4, 3),
    ((SELECT id FROM learning_modules WHERE code='DER-05'), 'DER-05-LO04', 'Calculate and interpret the value of a forward contract at initiation, during its life, and at expiration for both the long and short counterparties.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='DER-05'), 'DER-05-LO05', 'Describe the cost-of-carry model and analyze how each component — financing cost, storage costs, convenience yield, and income from the underlying — affects the forward price relative to the spot price.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='DER-05'), 'DER-05-LO06', 'Explain how violations of the no-arbitrage forward price create cash-and-carry or reverse cash-and-carry arbitrage opportunities, and demonstrate the transactions required to exploit such mispricings.', 3, 6),
    ((SELECT id FROM learning_modules WHERE code='DER-05'), 'DER-05-LO07', 'Compare the pricing and valuation of forward contracts across different underlying asset classes — equities with discrete dividends, currencies, and commodities — identifying how asset-specific carry benefits and costs alter the no-arbitrage forward price.', 4, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='DER-06'), 'DER-06-LO01', 'Explain how the no-arbitrage principle determines futures prices and describe the cash-and-carry arbitrage mechanism that enforces convergence between futures and spot prices.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='DER-06'), 'DER-06-LO02', 'Calculate the no-arbitrage futures price for financial and commodity underlyings given the spot price, risk-free rate, storage costs, convenience yields, and other carry costs or benefits.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='DER-06'), 'DER-06-LO03', 'Distinguish between the value and the price of a futures contract and explain why the value of a futures contract is reset to zero upon daily mark-to-market settlement.', 2, 3),
    ((SELECT id FROM learning_modules WHERE code='DER-06'), 'DER-06-LO04', 'Determine the current value of a long or short futures position between settlement dates given changes in the futures price, and calculate the cumulative gain or loss resulting from daily mark-to-market cash flows over the life of the contract.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='DER-06'), 'DER-06-LO05', 'Compare the pricing of futures contracts to the pricing of otherwise equivalent forward contracts, and analyze how mark-to-market settlement and the correlation between futures prices and interest rates can cause futures and forward prices to differ.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='DER-06'), 'DER-06-LO06', 'Apply the cost-of-carry model to calculate futures prices for equity index, fixed-income, currency, and commodity underlyings, incorporating dividends, coupon income, foreign risk-free rates, and convenience yields as appropriate.', 3, 6),
    ((SELECT id FROM learning_modules WHERE code='DER-06'), 'DER-06-LO07', 'Analyze the roles of expected future spot prices, risk premiums, and the cost-of-carry model in explaining the relationship between futures prices and expected spot prices, including the concepts of normal backwardation and contango.', 4, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='DER-07'), 'DER-07-LO01', 'Describe the structure of a plain vanilla interest rate swap, including the roles of the fixed-rate payer and floating-rate payer, payment netting, and the determination of settlement cash flows.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='DER-07'), 'DER-07-LO02', 'Explain how an interest rate swap can be replicated as a portfolio of bonds or a series of forward rate agreements (FRAs), and identify the no-arbitrage conditions that link swap pricing to these instruments.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='DER-07'), 'DER-07-LO03', 'Calculate the fixed swap rate (par rate) that sets the value of a plain vanilla interest rate swap to zero at initiation, using the present values of expected floating cash flows derived from market discount factors or LIBOR/SOFR forward rates.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='DER-07'), 'DER-07-LO04', 'Determine the market value of an interest rate swap to each counterparty after initiation, given a change in the term structure of interest rates, by discounting the remaining net cash flows at current market rates.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='DER-07'), 'DER-07-LO05', 'Distinguish between the price and the value of an interest rate swap, explaining why the price (fixed rate) is set at initiation so that value equals zero and how value subsequently deviates from zero as market rates change.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='DER-07'), 'DER-07-LO06', 'Analyze how the tenor, payment frequency, day-count convention, and notional principal affect the fixed rate and periodic settlement amounts of an interest rate swap.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='DER-07'), 'DER-07-LO07', 'Interpret the relationship between the swap fixed rate and par bond yields, and evaluate how shifts in the yield curve affect the relative gain or loss position of each counterparty over the life of the swap.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='DER-08'), 'DER-08-LO01', 'Describe the boundary conditions and factors that determine the minimum value and price bounds for European and American call and put options, including the effects of the underlying price, exercise price, time to expiration, volatility, risk-free rate, and cash flows on the underlying.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='DER-08'), 'DER-08-LO02', 'Explain put–call parity for European options and demonstrate how violations of put–call parity create arbitrage opportunities using portfolios of calls, puts, the underlying asset, and risk-free bonds.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='DER-08'), 'DER-08-LO03', 'Calculate the no-arbitrage value of European call and put options using the binomial option pricing model with one and two periods, incorporating risk-neutral probabilities and discounting at the risk-free rate.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='DER-08'), 'DER-08-LO04', 'Distinguish between the valuation of European and American options, explaining the conditions under which early exercise of American calls and puts may be optimal and how the possibility of early exercise affects relative option values.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='DER-08'), 'DER-08-LO05', 'Interpret the five inputs to the Black–Scholes–Merton option pricing model—underlying price, exercise price, time to expiration, risk-free rate, and volatility—and analyze the directional effect of a change in each input on call and put option values.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='DER-08'), 'DER-08-LO06', 'Define the option Greeks—delta, gamma, theta, vega, and rho—and explain how each measures the sensitivity of an option''s value to changes in a specific pricing input, including the practical use of delta for hedging.', 2, 6),
    ((SELECT id FROM learning_modules WHERE code='DER-08'), 'DER-08-LO07', 'Evaluate the impact of cash flows on the underlying asset (dividends or convenience yields) and the cost of carry on option pricing, and apply put–call parity and binomial models to options on assets with known cash flows or yields.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='DER-09'), 'DER-09-LO01', 'Define put-call parity and explain the no-arbitrage relationship among the prices of a European call, a European put, the underlying asset, and a risk-free bond with identical expiration dates and strike prices.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='DER-09'), 'DER-09-LO02', 'Calculate the price of a synthetic European call, put, underlying asset, or risk-free bond by rearranging the put-call parity equation, given the prices of the remaining three instruments.', 3, 2),
    ((SELECT id FROM learning_modules WHERE code='DER-09'), 'DER-09-LO03', 'Demonstrate how to construct a synthetic long or short position in a European option or the underlying asset using combinations of the other instruments in the put-call parity relationship, specifying the required positions and cash flows at initiation and expiration.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='DER-09'), 'DER-09-LO04', 'Identify and analyze arbitrage opportunities that arise when put-call parity is violated, and describe the transactions required to exploit the mispricing and the resulting risk-free profit.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='DER-09'), 'DER-09-LO05', 'Explain how dividends on the underlying asset and the timing of cash flows affect the put-call parity relationship, and adjust the parity equation to account for the present value of expected dividends or other carry benefits.', 2, 5),
    ((SELECT id FROM learning_modules WHERE code='DER-09'), 'DER-09-LO06', 'Compare the payoff profiles of a fiduciary call and a protective put, and interpret their equivalence as the foundation of put-call parity.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='DER-09'), 'DER-09-LO07', 'Evaluate the limitations of applying put-call parity to American-style options, distinguishing the conditions under which early exercise premiums cause the strict parity relationship to break down.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='DER-10'), 'DER-10-LO01', 'Describe the structure of a one-period binomial model, including the up and down price moves, the risk-neutral probabilities, and the replicating portfolio approach used to value derivatives.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='DER-10'), 'DER-10-LO02', 'Explain how no-arbitrage conditions are used to derive the risk-neutral probabilities in a one-period binomial model and why these probabilities differ from real-world probabilities.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='DER-10'), 'DER-10-LO03', 'Calculate the no-arbitrage value of a European call or put option using a one-period binomial model, given the underlying asset''s up and down factors, the risk-free rate, and the option''s strike price.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='DER-10'), 'DER-10-LO04', 'Determine the composition and value of a replicating portfolio consisting of the underlying asset and a risk-free bond that replicates the payoff of a derivative in a one-period binomial framework.', 3, 4),
    ((SELECT id FROM learning_modules WHERE code='DER-10'), 'DER-10-LO05', 'Distinguish between the replicating portfolio approach and the risk-neutral pricing approach in the one-period binomial model, and demonstrate that both methods yield the same no-arbitrage derivative value.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='DER-10'), 'DER-10-LO06', 'Analyze how changes in the up factor, down factor, and risk-free rate affect the risk-neutral probabilities and the resulting no-arbitrage value of a derivative in a one-period binomial model.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='DER-10'), 'DER-10-LO07', 'Identify and explain the arbitrage opportunity that arises when a derivative is mispriced relative to its no-arbitrage value in a one-period binomial model, and describe the transactions required to exploit it.', 3, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='ALT-04'), 'ALT-04-LO01', 'Describe the principal forms of real estate investment—direct ownership, real estate limited partnerships, real estate investment trusts (REITs), and mortgage-backed securities—and distinguish their risk, return, liquidity, and control characteristics.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='ALT-04'), 'ALT-04-LO02', 'Explain the key drivers of real estate valuation, including the income approach, the sales comparison approach, and the cost approach, and identify the conditions under which each method is most appropriate.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='ALT-04'), 'ALT-04-LO03', 'Calculate net operating income (NOI), capitalization rate, and property value using the direct capitalization method, and interpret how changes in market rents, vacancy rates, and discount rates affect estimated property value.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='ALT-04'), 'ALT-04-LO04', 'Compare the investment characteristics of equity REITs, mortgage REITs, and hybrid REITs, including their sources of income, leverage profiles, tax treatment, and sensitivity to interest rate changes.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='ALT-04'), 'ALT-04-LO05', 'Describe the defining characteristics of infrastructure as an asset class—including asset types (economic vs. social), concession structures, revenue models, and inflation-linkage features—and explain how these characteristics affect the risk–return profile relative to other alternative investments.', 2, 5),
    ((SELECT id FROM learning_modules WHERE code='ALT-04'), 'ALT-04-LO06', 'Analyze the roles of real estate and infrastructure in a multi-asset portfolio, including their diversification benefits, inflation-hedging properties, and the impact of illiquidity and appraisal-based valuation on reported return smoothing and correlation estimates.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='ALT-04'), 'ALT-04-LO07', 'Evaluate the due diligence considerations specific to real estate and infrastructure investments, including regulatory and political risk, leverage and refinancing risk, environmental liabilities, and the alignment of interests between general partners and investors in private fund structures.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='ALT-05'), 'ALT-05-LO01', 'Describe the principal categories of natural resource investments, including timberland, farmland, and commodities, and explain how each generates returns through income, biological growth, price appreciation, and convenience yield.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='ALT-05'), 'ALT-05-LO02', 'Explain the sources of return for commodity investments, including spot price changes, roll yield, and collateral yield, and distinguish how each component contributes to total return in contango versus backwardation markets.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='ALT-05'), 'ALT-05-LO03', 'Calculate the total return on a commodity futures position by decomposing it into spot return, roll return, and collateral return, and interpret the impact of the futures curve shape on roll yield over time.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='ALT-05'), 'ALT-05-LO04', 'Compare the investment characteristics of timberland and farmland as natural resource asset classes, including their return drivers, inflation-hedging properties, liquidity constraints, and typical role within a diversified portfolio.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='ALT-05'), 'ALT-05-LO05', 'Analyze how supply and demand factors, storage costs, seasonality, and geopolitical risks affect commodity prices and the shape of the commodity futures term structure.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='ALT-05'), 'ALT-05-LO06', 'Evaluate the diversification and inflation-hedging benefits of natural resource investments within a multi-asset portfolio, including the conditions under which these benefits are most and least effective.', 5, 6),
    ((SELECT id FROM learning_modules WHERE code='ALT-05'), 'ALT-05-LO07', 'Distinguish among the methods of gaining exposure to natural resources—direct ownership, commodity futures, commodity-linked notes, and natural resource equities—and identify the key risks, costs, and return characteristics associated with each approach.', 4, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='ALT-06'), 'ALT-06-LO01', 'Describe the key characteristics of hedge funds, including their legal structure, investor eligibility requirements, fee arrangements, and regulatory environment relative to traditional investment vehicles.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='ALT-06'), 'ALT-06-LO02', 'Distinguish among major hedge fund strategies—including long/short equity, global macro, event-driven, relative value, and managed futures—by explaining their return drivers, typical instruments used, and market conditions under which each tends to outperform or underperform.', 4, 2),
    ((SELECT id FROM learning_modules WHERE code='ALT-06'), 'ALT-06-LO03', 'Calculate management fees, incentive fees, and net-of-fee returns for hedge funds given gross returns, fee structures, hurdle rates, and high-water mark provisions, and explain how these features affect investor outcomes.', 3, 3),
    ((SELECT id FROM learning_modules WHERE code='ALT-06'), 'ALT-06-LO04', 'Explain the role of leverage, short selling, and derivatives in hedge fund strategies and analyze how their use affects the risk–return profile and potential for both amplified gains and losses.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='ALT-06'), 'ALT-06-LO05', 'Evaluate the challenges of measuring hedge fund performance, including survivorship bias, backfill bias, illiquidity-induced return smoothing, and the limitations of using standard mean–variance metrics for non-normally distributed returns.', 5, 5),
    ((SELECT id FROM learning_modules WHERE code='ALT-06'), 'ALT-06-LO06', 'Compare funds of hedge funds with direct hedge fund investment by analyzing diversification benefits, fee layering, due diligence advantages, and the impact on net investor returns.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='ALT-06'), 'ALT-06-LO07', 'Identify the primary risks associated with hedge fund investing—including counterparty risk, liquidity risk, operational risk, and strategy-specific risks—and describe the due diligence considerations relevant to allocating capital to hedge funds.', 2, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='ALT-07'), 'ALT-07-LO01', 'Describe the defining characteristics of digital assets, including the roles of distributed ledger technology, cryptographic security, and consensus mechanisms in establishing ownership and enabling trustless transactions.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='ALT-07'), 'ALT-07-LO02', 'Distinguish among the major categories of digital assets—cryptocurrencies, stablecoins, utility tokens, security tokens, and non-fungible tokens (NFTs)—by their structure, purpose, and economic rights conferred to holders.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='ALT-07'), 'ALT-07-LO03', 'Explain how proof-of-work and proof-of-stake consensus mechanisms differ with respect to energy consumption, security assumptions, validator incentives, and scalability implications for a blockchain network.', 2, 3),
    ((SELECT id FROM learning_modules WHERE code='ALT-07'), 'ALT-07-LO04', 'Calculate and interpret the annualized return, volatility, and Sharpe ratio of a digital asset position, and analyze how the inclusion of digital assets affects the risk-return profile and correlation structure of a traditional multi-asset portfolio.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='ALT-07'), 'ALT-07-LO05', 'Identify the primary sources of risk specific to digital asset investments—including protocol risk, counterparty and custody risk, regulatory risk, liquidity risk, and fork risk—and evaluate how each risk source affects the expected return distribution of a digital asset holding.', 5, 5),
    ((SELECT id FROM learning_modules WHERE code='ALT-07'), 'ALT-07-LO06', 'Compare the valuation approaches applicable to digital assets, including cost-of-production models, network-value-to-transactions (NVT) ratio, and Metcalfe''s Law-based frameworks, and explain the limitations of each approach relative to traditional asset valuation methods.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='ALT-07'), 'ALT-07-LO07', 'Describe the regulatory and institutional infrastructure surrounding digital assets, including the roles of centralized exchanges, decentralized exchanges (DEXs), custodians, and regulatory bodies, and explain how regulatory developments affect investor access, market integrity, and asset classification.', 2, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='PM-05'), 'PM-05-LO01', 'Distinguish between cognitive errors and emotional biases, and explain why emotional biases are generally harder to correct than cognitive errors in an investment context.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='PM-05'), 'PM-05-LO02', 'Describe the key cognitive errors—including anchoring and adjustment, availability, representativeness, illusion of control, conservatism, confirmation, hindsight, and framing biases—and identify how each can distort investment decision-making.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='PM-05'), 'PM-05-LO03', 'Describe the key emotional biases—including loss aversion, overconfidence, self-control, status quo, endowment, and regret-aversion biases—and explain how each can lead to suboptimal portfolio construction or trading behavior.', 2, 3),
    ((SELECT id FROM learning_modules WHERE code='PM-05'), 'PM-05-LO04', 'Analyze a given investor scenario to identify the specific behavioral biases present, classify each as cognitive or emotional, and evaluate the likely impact on the investor''s portfolio decisions.', 4, 4),
    ((SELECT id FROM learning_modules WHERE code='PM-05'), 'PM-05-LO05', 'Compare the goals-based investing framework with traditional mean–variance optimization, and explain how goals-based approaches can accommodate behavioral biases while still pursuing efficient portfolio outcomes.', 2, 5),
    ((SELECT id FROM learning_modules WHERE code='PM-05'), 'PM-05-LO06', 'Apply the concept of loss aversion to explain the disposition effect—the tendency to sell winners too early and hold losers too long—and determine how this behavior affects portfolio performance and tax efficiency.', 3, 6),
    ((SELECT id FROM learning_modules WHERE code='PM-05'), 'PM-05-LO07', 'Evaluate the trade-off between adapting to and moderating an investor''s behavioral biases, and recommend an appropriate advisory response given the investor''s wealth level, the severity of the bias, and the potential cost to long-term financial goals.', 5, 7);
INSERT INTO learning_outcomes (module_id, code, description, bloom_level, sort_order) VALUES
    ((SELECT id FROM learning_modules WHERE code='PM-06'), 'PM-06-LO01', 'Define risk management and explain how it differs from risk avoidance, describing the role of risk management in creating and preserving value within an organization.', 2, 1),
    ((SELECT id FROM learning_modules WHERE code='PM-06'), 'PM-06-LO02', 'Identify and distinguish among the major categories of financial and non-financial risks—including market, credit, liquidity, operational, legal, regulatory, and reputational risks—and explain how each can affect an organization''s financial position.', 2, 2),
    ((SELECT id FROM learning_modules WHERE code='PM-06'), 'PM-06-LO03', 'Describe the risk management process, including risk identification, risk measurement, risk modification, and monitoring, and explain how these steps interact within an enterprise risk management framework.', 2, 3),
    ((SELECT id FROM learning_modules WHERE code='PM-06'), 'PM-06-LO04', 'Calculate and interpret value at risk (VaR) given a portfolio''s expected return, standard deviation, and a specified confidence level, and evaluate the limitations of VaR as a standalone risk measure.', 5, 4),
    ((SELECT id FROM learning_modules WHERE code='PM-06'), 'PM-06-LO05', 'Compare and contrast risk modification strategies—risk prevention and avoidance, risk acceptance, risk transfer, and risk shifting—and determine the most appropriate strategy given a specific risk exposure and organizational objective.', 4, 5),
    ((SELECT id FROM learning_modules WHERE code='PM-06'), 'PM-06-LO06', 'Explain how derivatives, insurance, and diversification function as risk management tools, and analyze the trade-offs among cost, effectiveness, and residual risk for each approach.', 4, 6),
    ((SELECT id FROM learning_modules WHERE code='PM-06'), 'PM-06-LO07', 'Evaluate the key features of an effective risk governance framework, including the roles of the board of directors, senior management, and risk officers, and identify characteristics that distinguish strong risk culture from weak risk culture within an organization.', 5, 7);
